#include <cassert>
#include <iostream>

class IntArray
{
    int* m_data{};
    int m_size{};
    int m_capacity{};

public:
    IntArray(int capacity)
        : m_data{ new int[capacity]{} }
        , m_size{ 0 }
        , m_capacity{ capacity }
    {
    }

    ~IntArray()
    {
        delete[] m_data;
    }

    void push_back(int val)
    {
        assert(m_size < m_capacity);
        m_data[m_size] = val;
        ++m_size;
    }

    int get(int index) const
    {
        assert(index >= 0 && index < m_size);
        return m_data[index];
    }

    int size() const
    {
        return m_size;
    }
};

int main()
{
    int capacity{};
    int n{};
    std::cin >> capacity >> n;

    IntArray arr{ capacity };

    for (int i{ 0 }; i < n; ++i)
    {
        int val{};
        std::cin >> val;
        arr.push_back(val);
    }

    std::cout << "size: " << arr.size() << '\n';
    for (int i{ 0 }; i < arr.size(); ++i)
        std::cout << arr.get(i) << '\n';

    return 0;
}

