solution_code:
#include <cassert>
#include <iostream>
#include <string>

class IntStack
{
    int* m_data{};
    int m_size{};
    int m_capacity{};

public:
    IntStack(int capacity)
        : m_data{ new int[capacity]{} }
        , m_size{ 0 }
        , m_capacity{ capacity }
    {
    }

    ~IntStack()
    {
        delete[] m_data;
    }

    void push(int val)
    {
        assert(m_size < m_capacity);
        m_data[m_size] = val;
        ++m_size;
    }

    int pop()
    {
        assert(m_size > 0);
        --m_size;
        return m_data[m_size];
    }

    int top() const
    {
        assert(m_size > 0);
        return m_data[m_size - 1];
    }

    int size() const
    {
        return m_size;
    }
};

int main()
{
    int capacity{};
    int q{};
    std::cin >> capacity >> q;

    IntStack stack{ capacity };

    for (int i{ 0 }; i < q; ++i)
    {
        std::string cmd{};
        std::cin >> cmd;

        if (cmd == "push")
        {
            int val{};
            std::cin >> val;
            stack.push(val);
        }
        else if (cmd == "pop")
        {
            std::cout << stack.pop() << '\n';
        }
        else if (cmd == "top")
        {
            std::cout << stack.top() << '\n';
        }
        else if (cmd == "size")
        {
            std::cout << stack.size() << '\n';
        }
    }

    return 0;
}
